function decodeTrendLog(buffer) {
    const records = [];
    const buf = Array.from(buffer);
    let i = 0;
    while (i + 21 < buf.length) {
        if (buf[i] !== 14 || buf[i+1] !== 164) { i++; continue; }
        if (buf[i+20] !== 4 || buf[i+21] !== 0) { i++; continue; }
        const year   = 1900 + buf[i+2];
        const month  = buf[i+3];
        const day    = buf[i+4];
        const hour   = buf[i+7];
        const minute = buf[i+8];
        const second = buf[i+9];
        const timestamp = `${year}-${String(month).padStart(2,'0')}-${String(day).padStart(2,'0')} ${String(hour).padStart(2,'0')}:${String(minute).padStart(2,'0')}:${String(second).padStart(2,'0')}`;
        const valBuffer = Buffer.from(buf.slice(i+14, i+18));
        const value = parseFloat(valBuffer.readFloatBE(0).toFixed(4));
        records.push({ timestamp, value });
        i += 22;
    }
    return records;
}

async function main() {
    try {
        const dateFrom = new Date('2026-03-03T10:00:00');
        const chunkSize = 20;

        const recordCountResult = await client.readProperty(
            address,
            { type: bacnet.ObjectType.TREND_LOG, instance: 300001 },
            bacnet.PropertyIdentifier.RECORD_COUNT
        );
        const totalCount = recordCountResult.values?.[0]?.value;
        node.warn(`RECORD_COUNT: ${totalCount}`);

        let allRecords = [];
        let currentIndex = totalCount;
        let done = false;
        let chunk = 0;

        while (currentIndex > 0 && !done) {
            chunk++;
            const startIndex = Math.max(1, currentIndex - chunkSize + 1);
            const count = currentIndex - startIndex + 1;

            node.warn(`Chunk ${chunk}: readRange [${startIndex} → ${currentIndex}] (${count} entrées)`);

            const response = await client.readRange(
                address,
                { type: bacnet.ObjectType.TREND_LOG, instance: 300001 },
                startIndex, count,
                { maxSegments: bacnet.MaxSegmentsAccepted.SEGMENTS_65 }
            );

            const records = decodeTrendLog(response.rangeBuffer);
            node.warn(`Chunk ${chunk}: décodé ${records.length} entrées | ${records[0]?.timestamp} → ${records[records.length-1]?.timestamp}`);

            const filtered = records.filter(r => new Date(r.timestamp) >= dateFrom);
            node.warn(`Chunk ${chunk}: ${filtered.length} entrées >= dateFrom`);
            allRecords = filtered.concat(allRecords);

            if (filtered.length < records.length) {
                node.warn(`Chunk ${chunk}: dateFrom atteinte, arrêt`);
                done = true;
            }

            currentIndex = startIndex - 1;
        }

        node.warn(`RÉSULTAT: ${allRecords.length} enregistrements`);
        node.send({ payload: allRecords });

    } catch (err) {
        node.error('Erreur: ' + err.message);
    } finally {

    }
}

