async function main() {
    try {
        const value = await client.readProperty(
            address,
            { type: bacnet.ObjectType.SCHEDULE, instance: 5001 },
            bacnet.PropertyIdentifier.EXCEPTION_SCHEDULE
        );

        node.warn('RAW VALUE: ' + JSON.stringify(value, null, 2));

        const exceptions = (value.values[0]?.value) || [];

        const result = exceptions.map((specialEvent, index) => {
            // Inspecter chaque événement brut

            // La structure peut être à un niveau différent selon le device/lib
            const raw = specialEvent?.value ?? specialEvent;
            const period = raw?.period ?? raw?.calendarEntry ?? raw;
            const timeValues = (raw?.listOfTimeValues || raw?.timeValues || []).map(tv => ({
                time: tv?.time,
                value: tv?.value
            }));
            node.warn(raw);
            return {
                index,
                raw,
                period,
                timeValues,
                priority: raw?.eventPriority ?? raw?.priority
            };

        });

        node.send({ payload: result });

    } catch (err) {
        node.error('Erreur: ' + JSON.stringify(err, Object.getOwnPropertyNames(err)));
    } finally {
        client.close();
    }
}

